module regamma(datain, dataout, load, initialize, clock);
input [4:0] datain;
input load, initialize;
input clock;
output [4:0] dataout;
reg [4:0] obf_out;
always @(posedge clock)
begin
    if(initialize)
       obf_out <= 5'b10000;
    else if(load)
       obf_out <= datain;
    else
       obf_out <= 5'b0;
end
assign dataout = obf_out;
endmodule
